import { invokeFunction } from "../../utils/zcutils";

/**
 *
 * @param instanceMap
 * @param event
 * @constructor
 */
export function ZCChartScrollListener(instanceMap, event) {
    let eventManager = this,
        eventHandler = this.chart.eventHandler,
        oldBrush = eventHandler.oldBrushComponent,
        activeBrush = eventHandler.activeBrushComponent;
    if (!(oldBrush === null && activeBrush === null)) {
        eventHandler.oldBrushComponent = activeBrush;
        eventHandler.activeBrushComponent = 'scroll';
    }


    let race = this.chart.racing,
        selection = race && race.scrollView && race.raceMode === "auto" ? invokeFunction(race.scrollView, null, true) || event.selection : event.selection,
        data = eventManager.getData(instanceMap, event.type, selection),
        last = eventManager.chart.cache.scroll.selection;

    // if (last && selection && selection[0] === last[0] && selection[1] === last[1]) {
    //     return;
    // }

    // if data fire
    eventManager.associateBehaviours(instanceMap, event.type, data, event.selection, event);
}
